template.css_template:
#{{ID}} .ticker-vert-container {
position: absolute;
top: 0;
left: 0;
width: var(--v-width, 100%);
height: var(--v-height, 60px);
display: flex;
align-items: stretch;
background: {{PRIMARY_BG}};
border: {{BORDER_WIDTH}}px solid {{BORDER_COLOR}};
border-radius: {{BORDER_RADIUS}}px;
font-family: '{{FONT_FAMILY}}', sans-serif;
box-shadow: {{BOX_SHADOW}};
opacity: 0;
transform: {{ANIMATION_IN_TRANSFORM}};
transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
overflow: hidden;
}
#{{ID}} .ticker-vert-label {
background: {{BORDER_COLOR}};
color: {{TITLE_COLOR}};
padding: 0 25px;
display: flex;
align-items: center;
font-weight: 800;
font-size: {{FONT_SIZE}}px;
text-transform: uppercase;
letter-spacing: 1px;
flex-shrink: 0;
border-right: 2px solid rgba(0,0,0,0.15);
}
#{{ID}} .ticker-vert-viewport {
flex: 1;
position: relative;
overflow: hidden;
}
#{{ID}} .ticker-vert-item {
position: absolute;
width: 100%;
padding: 0 25px;
height: 100%;
display: flex;
align-items: center;
color: {{TITLE_COLOR}};
font-size: {{FONT_SIZE}}px;
font-weight: {{TITLE_WEIGHT}};
text-transform: {{TITLE_TRANSFORM}};
white-space: nowrap;
opacity: 0;
transform: translateY(100%);
}
#{{ID}} .ticker-vert-item.entering {
animation: ticker-vert-in 0.5s ease-out forwards;
}
#{{ID}} .ticker-vert-item.leaving {
animation: ticker-vert-out 0.5s ease-in forwards;
}
@keyframes ticker-vert-in {
from { transform: translateY(100%); opacity: 0; }
to { transform: translateY(0); opacity: 1; }
}
@keyframes ticker-vert-out {
from { transform: translateY(0); opacity: 1; }
to { transform: translateY(-100%); opacity: 0; }
}

template.js_template:
(() => {
  const root = document.getElementById("{{ID}}");
  const container = root.querySelector('.ticker-vert-container');
  const viewport = root.querySelector('.ticker-vert-viewport');
  const label = root.querySelector('.ticker-vert-label');
  const dataEl = root.querySelector('.ticker-vert-data');
  if (!container || !viewport || !dataEl) return;

  const DEFAULT_WIPER = "{{WIPER_TEXT}}";

  let items = [];
  try { items = JSON.parse(dataEl.textContent || '[]'); } catch(e) { items = ['BRAK DANYCH']; }
  if (!items.length) items = ['BRAK WIADOMOŚCI'];

  let currentIndex = 0;
  let cycleRunning = false;
  let cycleTimer = null;
  const displayMs = Math.max(1000, (parseFloat("{{TICKER_SPEED}}") || 5) * 1000);

  function runCycle() {
    if (!cycleRunning || !viewport) return;
    const el = document.createElement('div');
    el.className = 'ticker-vert-item';

    const currentItem = items[currentIndex];
    const text = typeof currentItem === 'object' ? (currentItem.text || "") : currentItem;
    const category = typeof currentItem === 'object' ? (currentItem.category || "") : "";

    el.textContent = text;

    const labelText = (category || "").trim() || (DEFAULT_WIPER || "").trim();
    if (label) {
        label.style.display = labelText ? 'flex' : 'none';
        label.innerText = labelText;
    }

    viewport.appendChild(el);
    void el.offsetWidth;
    el.classList.add('entering');

    cycleTimer = setTimeout(() => {
      if (!cycleRunning) { if (el.parentNode) el.parentNode.removeChild(el); return; }
      el.classList.remove('entering');
      el.classList.add('leaving');
      currentIndex = (currentIndex + 1) % items.length;
      setTimeout(() => {
        if (el.parentNode) el.parentNode.removeChild(el);
        if (cycleRunning) runCycle();
      }, 500);
    }, displayMs);
  }

  root.__slt_show = () => {
    const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
    tl.add(() => { cycleRunning = true; setTimeout(runCycle, 100); });
    return tl;
  };

  root.__slt_hide = () => {
    cycleRunning = false;
    if (cycleTimer) clearTimeout(cycleTimer);
    viewport.querySelectorAll('.ticker-vert-item').forEach(i => i.parentNode && i.parentNode.removeChild(i));
    return GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
  };
})();
